"use client"

import React from 'react'
import { cn } from '@/lib/utils'
import type { PropostaTemplateData, FuncionalidadeItem, MembroEquipe, CondicaoPagamento } from '@/lib/proposta-template-types'

interface ProposalTemplateRendererProps {
  data: PropostaTemplateData
  className?: string
}

export function ProposalTemplateRenderer({ data, className }: ProposalTemplateRendererProps) {
  return (
    <div className={cn("w-full max-w-[210mm] mx-auto bg-background", className)}>
      {/* DOCUMENTO CONTÍNUO */}
      <div className="relative bg-background shadow-md">
        {/* BACKGROUND WATERMARK */}
        <div
          className="fixed inset-0 opacity-[0.035] pointer-events-none z-0"
          style={{
            backgroundImage: 'url(/fundo-center.png)',
            backgroundPosition: 'center center',
            backgroundRepeat: 'no-repeat',
            backgroundSize: '602px auto',
          }}
        />

        {/* CONTEÚDO */}
        <div className="relative z-10 px-14 py-14 space-y-8">
          {/* === HEADER/CAPA === */}
          <CapaSection data={data} />

          {/* === SOBRE A EMPRESA === */}
          <EmpresaSection data={data.empresa} />

          {/* === SOBRE O PROJETO === */}
          <ProjetoSection data={data.projeto} />

          {/* === FUNCIONALIDADES === */}
          <FuncionalidadesSection data={data.funcionalidades} />

          {/* === INTEGRAÇÕES === */}
          {data.integracoes && (
            <IntegracoesSection data={data.integracoes} />
          )}

          {/* === MODELO DE TRABALHO === */}
          <ModeloTrabalhoSection data={data.modeloTrabalho} />

          {/* === EQUIPE === */}
          <EquipeSection data={data.equipe} />

          {/* === CRONOGRAMA === */}
          <CronogramaSection data={data.cronograma} />

          {/* === INVESTIMENTO === */}
          <InvestimentoSection data={data.investimento} />

          {/* === ENTREGÁVEIS === */}
          <EntregaveisSection data={data.entregaveis} />

          {/* === PRÓXIMOS PASSOS === */}
          <ProximosPassosSection data={data.proximosPassos} />

          {/* === ENCERRAMENTO === */}
          <EncerramentoSection data={data.encerramento} />
        </div>
      </div>
    </div>
  )
}

// === COMPONENTES DE SEÇÃO ===

function CapaSection({ data }: { data: PropostaTemplateData }) {
  return (
    <header className="space-y-8">
      {/* LOGO */}
      <div className="flex justify-start">
        <img
          src="/logo-completa.png"
          alt="Wa Project Logo"
          width={120}
          height={36}
          className="h-9 w-auto object-contain"
        />
      </div>

      {/* TÍTULOS */}
      <div className="space-y-2">
        <h1 className="text-2xl font-bold text-[color:var(--wa-brand-primary)] leading-tight">
          {data.capa.titulo}
        </h1>
        <h2 className="text-2xl font-bold text-[color:var(--wa-brand-primary)] leading-tight">
          {data.capa.subtitulo}
        </h2>
      </div>

      {/* INFO DA CAPA */}
      <div className="space-y-1">
        <div className="text-sm font-medium text-foreground">
          {data.capa.dataEmissao} | Válido por {data.capa.validadeDias} dias
        </div>
        <p className="text-sm text-foreground">
          <strong>Para:</strong> {data.capa.cliente.empresa}
        </p>
        {data.capa.cliente.pessoa && (
          <p className="text-sm text-foreground">
            <strong>Empresa:</strong> {data.capa.cliente.pessoa}
          </p>
        )}
        <p className="text-sm text-foreground">
          <strong>Tipo:</strong> {data.capa.tipoEscopo}
        </p>
      </div>
    </header>
  )
}

function EmpresaSection({ data }: { data: PropostaTemplateData['empresa'] }) {
  return (
    <section className="space-y-4">
      <SectionTitle>Sobre a {data.nome}</SectionTitle>
      <p className="text-sm text-muted-foreground leading-relaxed">
        {data.descricao}
      </p>

      <div className="space-y-2">
        <h3 className="text-sm font-bold text-foreground">Nossos serviços:</h3>
        <ul className="list-disc pl-5 space-y-1">
          {data.servicos.map((servico) => (
            <li key={servico} className="text-sm text-muted-foreground leading-relaxed">
              {servico}
            </li>
          ))}
        </ul>
      </div>

      <div className="space-y-2">
        <SectionTitle>Nossos Clientes</SectionTitle>
        <ul className="list-disc pl-5 space-y-1">
          {data.clientes.map((cliente) => (
            <li key={cliente} className="text-sm text-muted-foreground leading-relaxed">
              {cliente}
            </li>
          ))}
        </ul>
        {data.websiteCases && (
          <p className="text-sm text-muted-foreground leading-relaxed">
            Cases completos: {data.websiteCases}
          </p>
        )}
      </div>
    </section>
  )
}

function ProjetoSection({ data }: { data: PropostaTemplateData['projeto'] }) {
  return (
    <section className="space-y-4">
      <SectionTitle>{data.titulo}</SectionTitle>
      <h3 className="text-sm font-bold text-foreground">{data.nome}</h3>
      <p className="text-sm text-muted-foreground leading-relaxed">
        {data.descricao}
      </p>
      {data.objetivo && (
        <p className="text-sm text-muted-foreground leading-relaxed">
          {data.objetivo}
        </p>
      )}
    </section>
  )
}

function FuncionalidadesSection({ data }: { data: PropostaTemplateData['funcionalidades'] }) {
  return (
    <section className="space-y-4">
      <SectionTitle>{data.titulo}</SectionTitle>
      <div className="space-y-4">
        {data.itens.map((item: FuncionalidadeItem) => (
          <FuncionalidadeItem key={item.numero} item={item} />
        ))}
      </div>
    </section>
  )
}

function FuncionalidadeItem({ item }: { item: FuncionalidadeItem }) {
  return (
    <div className="space-y-1">
      <p className="text-sm text-muted-foreground leading-relaxed">
        <strong className="text-foreground">{item.numero}. {item.titulo}</strong> - {item.descricao}
      </p>
    </div>
  )
}

function IntegracoesSection({ data }: { data: NonNullable<PropostaTemplateData['integracoes']> }) {
  return (
    <section className="space-y-4">
      <SectionTitle>{data.titulo}</SectionTitle>
      <p className="text-sm text-muted-foreground leading-relaxed">
        {data.descricao}
      </p>
      {data.itens && data.itens.length > 0 && (
        <ul className="list-disc pl-5 space-y-1">
          {data.itens.map((item, index) => (
            <li key={index} className="text-sm text-muted-foreground leading-relaxed">
              {item}
            </li>
          ))}
        </ul>
      )}
    </section>
  )
}

function ModeloTrabalhoSection({ data }: { data: PropostaTemplateData['modeloTrabalho'] }) {
  return (
    <section className="space-y-4">
      <SectionTitle>{data.titulo}</SectionTitle>
      <p className="text-sm text-muted-foreground leading-relaxed">
        <strong className="text-foreground">{data.tipo}</strong> - {data.descricao}
      </p>

      <div className="space-y-2">
        <h3 className="text-sm font-bold text-foreground">Fases do Projeto:</h3>
        <div className="space-y-1">
          {data.fases.map((fase) => (
            <div key={fase.numero} className="text-sm text-muted-foreground leading-relaxed">
              <strong className="text-foreground">Fase {fase.numero}:</strong> {fase.nome} - {fase.descricao}
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

function EquipeSection({ data }: { data: PropostaTemplateData['equipe'] }) {
  return (
    <section className="space-y-4">
      <SectionTitle>{data.titulo}</SectionTitle>
      <p className="text-sm text-muted-foreground leading-relaxed">
        {data.descricao}
      </p>

      <div className="space-y-5">
        {data.membros.map((membro: MembroEquipe, index) => (
          <MembroEquipeItem key={index} membro={membro} />
        ))}
      </div>
    </section>
  )
}

function MembroEquipeItem({ membro }: { membro: MembroEquipe }) {
  return (
    <div className="space-y-2">
      <h4 className="text-sm font-bold text-[color:var(--wa-brand-primary)]">
        {membro.cargo}
      </h4>
      <p className="text-sm text-muted-foreground leading-relaxed">
        {membro.descricao}
      </p>
    </div>
  )
}

function CronogramaSection({ data }: { data: PropostaTemplateData['cronograma'] }) {
  return (
    <section className="space-y-4">
      <SectionTitle>{data.titulo}</SectionTitle>
      <p className="text-base font-bold text-foreground">
        {data.prazoTotal}
      </p>

      {data.fases && data.fases.length > 0 && (
        <div className="space-y-1">
          {data.fases.map((fase, index) => (
            <div key={index} className="text-sm text-muted-foreground leading-relaxed">
              <strong className="text-foreground">{fase.fase}:</strong> {fase.nome}: {fase.periodo}
            </div>
          ))}
        </div>
      )}

      {data.observacoes && (
        <p className="text-sm text-muted-foreground leading-relaxed">
          {data.observacoes}
        </p>
      )}
    </section>
  )
}

function InvestimentoSection({ data }: { data: PropostaTemplateData['investimento'] }) {
  return (
    <section className="space-y-4">
      <SectionTitle>{data.titulo}</SectionTitle>
      <p className="text-base font-bold text-foreground">
        Investimento total: {data.valorTotal}
      </p>

      <div className="space-y-2">
        <h3 className="text-sm font-bold text-foreground">Condições de Pagamento:</h3>
        <div className="space-y-1">
          {data.condicoesPagamento.map((condicao: CondicaoPagamento, index) => (
            <div key={index} className="text-sm text-muted-foreground leading-relaxed">
              <strong className="text-foreground">{condicao.parcela}:</strong> {condicao.momento}: {condicao.valor}
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

function EntregaveisSection({ data }: { data: PropostaTemplateData['entregaveis'] }) {
  return (
    <section className="space-y-4">
      <SectionTitle>{data.titulo}</SectionTitle>
      <ul className="list-disc pl-5 space-y-1">
        {data.itens.map((item, index) => (
          <li key={index} className="text-sm text-muted-foreground leading-relaxed">
            {item}
          </li>
        ))}
      </ul>
    </section>
  )
}

function ProximosPassosSection({ data }: { data: PropostaTemplateData['proximosPassos'] }) {
  return (
    <section className="space-y-4">
      <SectionTitle>{data.titulo}</SectionTitle>
      <ol className="list-decimal pl-5 space-y-2">
        {data.passos.map((passo, index) => (
          <li key={index} className="text-sm text-muted-foreground leading-relaxed">
            {passo}
          </li>
        ))}
      </ol>

      {data.observacao && (
        <p className="text-sm text-muted-foreground leading-relaxed">
          {data.observacao}
        </p>
      )}
    </section>
  )
}

function EncerramentoSection({ data }: { data: PropostaTemplateData['encerramento'] }) {
  return (
    <section className="space-y-6 pt-8">
      {/* CITAÇÕES */}
      <div className="space-y-2">
        <p className="text-base font-bold text-[color:var(--wa-brand-primary)]">
          {data.citacao1}
        </p>
        <p className="text-base font-bold text-[color:var(--wa-brand-primary)]">
          {data.citacao2}
        </p>
      </div>

      {/* INFORMAÇÕES DA EMPRESA */}
      <div className="space-y-1">
        <p className="text-sm text-muted-foreground">
          <strong className="text-foreground">{data.informacoesEmpresa.nomeCompleto}</strong>
        </p>
        <p className="text-sm text-muted-foreground">
          <strong>CNPJ:</strong> {data.informacoesEmpresa.cnpj}
        </p>
        <p className="text-sm text-muted-foreground">
          <strong>Website:</strong> {data.informacoesEmpresa.website}
        </p>
        <p className="text-sm text-muted-foreground">
          <strong>Email:</strong> {data.informacoesEmpresa.email}
        </p>
        <p className="text-sm text-muted-foreground">
          <strong>Telefone/WhatsApp:</strong> {data.informacoesEmpresa.telefone}
        </p>
      </div>

      {/* VALIDADE */}
      <div className="pt-4">
        <p className="text-xs text-muted-foreground">
          {data.textoValidade}
        </p>
      </div>
    </section>
  )
}

// === COMPONENTES AUXILIARES ===

function SectionTitle({ children }: { children: React.ReactNode }) {
  return (
    <h2 className="text-lg font-bold text-[color:var(--wa-brand-primary)] break-after-avoid">
      {children}
    </h2>
  )
}

export default ProposalTemplateRenderer

import { generateWaProjectProposalPDF, type WaProjectPDFGenerator } from './wa-project-pdf-generator'
import type { PropostaTemplateData, FuncionalidadeItem, MembroEquipe } from './proposta-template-types'
import type { ProposalSection } from './proposal-types'

/**
 * Gerador de PDF para propostas usando a nova estrutura
 * Converte dados estruturados para o formato esperado pelo WaProjectPDFGenerator
 */

interface PDFGenerationOptions {
  filename?: string
  download?: boolean // true = download automático, false = retorna blob
}

/**
 * Gera PDF da proposta a partir dos dados estruturados
 */
export async function gerarPDFProposta(
  data: PropostaTemplateData,
  options: PDFGenerationOptions = {}
): Promise<Blob | void> {
  try {
    // Converter dados estruturados para o formato do WaProjectPDFGenerator
    const proposalData = converterParaFormatoLegado(data)

    // Verificar se é download ou retorno de blob
    if (options.download === false) {
      // Retorna blob para preview ou outras operações
      return await gerarPDFBlob(proposalData)
    } else {
      // Download automático (comportamento padrão)
      const filename = options.filename || gerarNomeArquivo(data)
      await generateWaProjectProposalPDF({ ...proposalData, projeto: { nome: filename } })
    }
  } catch (error) {
    throw new Error(`Falha na geração do PDF: ${error instanceof Error ? error.message : 'Erro desconhecido'}`)
  }
}

/**
 * Converte PropostaTemplateData para o formato esperado pelo WaProjectPDFGenerator
 */
function converterParaFormatoLegado(data: PropostaTemplateData) {
  // Converter funcionalidades para seções
  const sections: ProposalSection[] = []

  // === SOBRE O PROJETO ===
  sections.push({
    key: 'projeto',
    title: data.projeto.titulo,
    content: `**${data.projeto.nome}**\n\n${data.projeto.descricao}${data.projeto.objetivo ? '\n\n' + data.projeto.objetivo : ''}`
  })

  // === FUNCIONALIDADES ===
  const funcionalidadesContent = data.funcionalidades.itens
    .map((item: FuncionalidadeItem) => `**${item.numero}. ${item.titulo}** - ${item.descricao}`)
    .join('\n\n')

  sections.push({
    key: 'funcionalidades',
    title: data.funcionalidades.titulo,
    content: funcionalidadesContent
  })

  // === INTEGRAÇÕES (se existir) ===
  if (data.integracoes) {
    const integracoesContent = data.integracoes.descricao +
      (data.integracoes.itens ? '\n\n' + data.integracoes.itens.map(item => `• ${item}`).join('\n') : '')

    sections.push({
      key: 'integracoes',
      title: data.integracoes.titulo,
      content: integracoesContent
    })
  }

  // === MODELO DE TRABALHO ===
  const fasesContent = data.modeloTrabalho.fases
    .map(fase => `**Fase ${fase.numero}:** ${fase.nome} - ${fase.descricao}`)
    .join('\n')

  sections.push({
    key: 'modelo',
    title: data.modeloTrabalho.titulo,
    content: `**${data.modeloTrabalho.tipo}** - ${data.modeloTrabalho.descricao}\n\n**Fases do Projeto:**\n${fasesContent}`
  })

  // === EQUIPE ===
  const equipeContent = data.equipe.descricao + '\n\n' +
    data.equipe.membros
      .map((membro: MembroEquipe) => `**${membro.cargo}**\n${membro.descricao}`)
      .join('\n\n')

  sections.push({
    key: 'equipe',
    title: data.equipe.titulo,
    content: equipeContent
  })

  // === CRONOGRAMA ===
  let cronogramaContent = data.cronograma.prazoTotal

  if (data.cronograma.fases && data.cronograma.fases.length > 0) {
    cronogramaContent += '\n\n' + data.cronograma.fases
      .map(fase => `**${fase.fase}:** ${fase.nome}: ${fase.periodo}`)
      .join('\n')
  }

  if (data.cronograma.observacoes) {
    cronogramaContent += '\n\n' + data.cronograma.observacoes
  }

  sections.push({
    key: 'cronograma',
    title: data.cronograma.titulo,
    content: cronogramaContent
  })

  // === INVESTIMENTO ===
  const investimentoContent = `**Investimento total:** ${data.investimento.valorTotal}\n\n` +
    '**Condições de Pagamento:**\n' +
    data.investimento.condicoesPagamento
      .map(condicao => `**${condicao.parcela}:** ${condicao.momento}: ${condicao.valor}`)
      .join('\n')

  sections.push({
    key: 'investimento',
    title: data.investimento.titulo,
    content: investimentoContent
  })

  // === ENTREGÁVEIS ===
  const entregaveisContent = data.entregaveis.itens
    .map(item => `• ${item}`)
    .join('\n')

  sections.push({
    key: 'entregaveis',
    title: data.entregaveis.titulo,
    content: entregaveisContent
  })

  // === PRÓXIMOS PASSOS ===
  const proximosPassosContent = data.proximosPassos.passos
    .map((passo, index) => `${index + 1}. ${passo}`)
    .join('\n') +
    (data.proximosPassos.observacao ? '\n\n' + data.proximosPassos.observacao : '')

  sections.push({
    key: 'proximos_passos',
    title: data.proximosPassos.titulo,
    content: proximosPassosContent
  })

  // Retornar no formato esperado pelo WaProjectPDFGenerator
  return {
    projeto: {
      nome: data.projeto.nome
    },
    data_emissao: data.capa.dataEmissao,
    validade_dias: data.capa.validadeDias.toString(),
    cliente: {
      nome: data.capa.cliente.empresa
    },
    tipo_escopo: data.capa.tipoEscopo,
    sections: sections,
    numeracao_pagina: "1"
  }
}

/**
 * Gera PDF como Blob para operações internas
 */
async function gerarPDFBlob(proposalData: any): Promise<Blob> {
  // Esta função precisaria ser implementada para retornar um Blob
  // Por agora, retorna uma Promise rejeitada pois o WaProjectPDFGenerator não suporta blob diretamente
  throw new Error('Geração de Blob não implementada ainda - apenas download automático está disponível')
}

/**
 * Gera nome de arquivo seguro baseado nos dados da proposta
 */
function gerarNomeArquivo(data: PropostaTemplateData): string {
  const clienteSlug = data.capa.cliente.empresa
    .replace(/[^a-zA-Z0-9\s]/g, '')
    .replace(/\s+/g, '_')
    .toLowerCase()

  const dataSlug = data.capa.dataEmissao.replace(/\//g, '-')

  return `proposta_${clienteSlug}_${dataSlug}`
}

/**
 * Valida dados antes da geração do PDF
 */
export function validarDadosParaPDF(data: PropostaTemplateData): { valido: boolean; erros: string[] } {
  const erros: string[] = []

  // Validações essenciais para PDF
  if (!data.capa?.titulo) erros.push('Título da capa é obrigatório')
  if (!data.capa?.subtitulo) erros.push('Subtítulo da capa é obrigatório')
  if (!data.capa?.dataEmissao) erros.push('Data de emissão é obrigatória')
  if (!data.capa?.cliente?.empresa) erros.push('Nome da empresa cliente é obrigatório')

  if (!data.projeto?.nome) erros.push('Nome do projeto é obrigatório')
  if (!data.projeto?.descricao) erros.push('Descrição do projeto é obrigatória')

  if (!data.funcionalidades?.itens?.length) erros.push('Pelo menos uma funcionalidade é obrigatória')

  if (!data.investimento?.valorTotal) erros.push('Valor total do investimento é obrigatório')
  if (!data.investimento?.condicoesPagamento?.length) erros.push('Condições de pagamento são obrigatórias')

  return {
    valido: erros.length === 0,
    erros
  }
}

// === FUNÇÕES AUXILIARES PARA IA ===

