// Função simples para sanitizar HTML básico (apenas bold)
function sanitizeBasicHtml(html: string): string {
  return html.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
}

// Renderer customizado para o conteúdo markdown
function WaProjectMarkdownRenderer({ content }: { content: string }) {
  // Processar o conteúdo markdown de forma simples
  const processedContent = content
    .split('\n')
    .map((line, index) => {
      const trimmed = line.trim()

      // Títulos
      if (trimmed.startsWith('### ')) {
        return <h3 key={index} className="text-base font-semibold text-wa-brand-primary mt-4 mb-2">{trimmed.slice(4)}</h3>
      }
      if (trimmed.startsWith('## ')) {
        return <h3 key={index} className="text-base font-semibold text-wa-brand-primary mt-4 mb-2">{trimmed.slice(3)}</h3>
      }
      if (trimmed.startsWith('# ')) {
        return <h3 key={index} className="text-base font-semibold text-wa-brand-primary mt-4 mb-2">{trimmed.slice(2)}</h3>
      }

      // Listas com bullet points
      if (trimmed.startsWith('• ') || trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
        const text = sanitizeBasicHtml(trimmed.slice(2))
        return <li key={index} className="text-sm text-foreground ml-4 mb-1" dangerouslySetInnerHTML={{ __html: text }} />
      }

      // Listas numeradas
      const numberedMatch = trimmed.match(/^(\d+)\.\s+(.+)$/)
      if (numberedMatch) {
        const text = sanitizeBasicHtml(numberedMatch[2])
        return (
          <div key={index} className="text-sm text-foreground mb-2">
            <strong>{numberedMatch[1]}.</strong> <span dangerouslySetInnerHTML={{ __html: text }} />
          </div>
        )
      }

      // Parágrafos
      if (trimmed && !trimmed.startsWith('-') && !trimmed.startsWith('|')) {
        const text = sanitizeBasicHtml(trimmed)
        return <p key={index} className="text-sm text-foreground mb-2" dangerouslySetInnerHTML={{ __html: text }} />
      }

      // Linhas vazias
      if (!trimmed) {
        return <br key={index} />
      }

      return null
    })
    .filter(Boolean)

  return <div>{processedContent}</div>
}

