          </Button>
          {/* Mark as Concluida - visible when Rascunho and has content */}
          {status === "Rascunho" && sections.length > 0 && onMarkConcluida && (
            <Button
              variant="outline"
              size="sm"
              onClick={handleMarkConcluida}
              className="border-[#16a34a]/30 text-[#16a34a] hover:bg-[#dcfce7]"
            >
              <CheckCircle className="mr-1.5 h-3.5 w-3.5" />
