          sections,
          numeracao_pagina: proposalNumber,
        }

        await generateWaProjectProposalPDF(proposalData)
      } else {
        // Usar o gerador clássico
        const tokens = buildProposalTokens({ empresa, para, projeto, modeloTrabalho, dataCriacao, sections })
        const filename = `Proposta_${empresa || 'Cliente'}_${formatDateShort(dataCriacao).replace(/\//g, '-')}.pdf`

        generateProposalPDF({ tokens, filename })
      }

      toast.success("PDF gerado com sucesso!")

    } catch (err) {
      console.error("[ProposalDocument] PDF error:", err)
      toast.error("Erro ao gerar o PDF. Tente novamente.")
    } finally {
      setDownloading(false)
    }
  }, [sections, useRefactoredTemplate, useWaTemplate, empresa, para, projeto, dataCriacao, modeloTrabalho, proposalNumber])

  const statusBadge = useMemo(() => {
    switch (status) {
      case "Aprovada":
        return <Badge variant="default">Aprovada</Badge>
      case "Concluída":
        return <Badge variant="secondary" className="bg-green-100 text-green-700 hover:bg-green-100">Concluída</Badge>
      case "Rascunho":
      default:
        return <Badge variant="outline" className="bg-yellow-50 text-yellow-700 hover:bg-yellow-50">Rascunho</Badge>
    }
  }, [status])

  // Memoizar dados convertidos para evitar recálculos desnecessários
  const templateData = useMemo(() =>
    converterPropostaParaTemplate({
      empresa,
      para,
      projeto,
      dataCriacao,
      sections,
      modeloTrabalho
    }), [empresa, para, projeto, dataCriacao, sections, modeloTrabalho]
  )

  // Memoizar handlers dos botões
